"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";
import { FFmpeg } from "@ffmpeg/ffmpeg";
import {
  AlertCircle,
  Download,
  LoaderCircle,
  Music,
  Pause,
  Play,
  WandSparkles,
} from "lucide-react";
import WaveSurfer from "wavesurfer.js";
import RegionsPlugin, {
  Region,
} from "wavesurfer.js/dist/plugins/regions.esm.js";
import useStateData from "@/hooks/useStateData";
import { encodeWAV } from "@/utils/encodeWave";

const Editor: React.FC = () => {
  const waveformRef = useRef<HTMLDivElement>(null);
  const wavesurferRef = useRef<WaveSurfer | null>(null);
  const regionsRef = useRef<RegionsPlugin | null>(null);
  const ffmpegRef = useRef<FFmpeg | null>(null);

  const [isPlaying, setIsPlaying] = useState<boolean>(false);
  const [ffmpegLoaded, setFFmpegLoaded] = useState<boolean>(false);
  const [waveformLoading, setWaveformLoading] = useState<boolean>(false);
  const [exportingFormat, setExportingFormat] = useState<
    "ios" | "android" | null
  >(null);
  const [editorMessage, setEditorMessage] = useState<string | null>(null);

  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [duration, setDuration] = useState<number>(0);

  const { data } = useStateData();
  const fileLoaded = Boolean(data);
  const fileName = data?.data.result.author.username ?? "";
  const proxiedAudioUrl = data
    ? `/api/audio?src=${encodeURIComponent(data.data.result.music.playUrl[0])}`
    : null;

  useEffect(() => {
    const loadFFmpeg = async () => {
      if (!ffmpegRef.current) {
        try {
          const ffmpeg = new FFmpeg();
          ffmpegRef.current = ffmpeg;

          ffmpeg.on("log", ({ message }) => {
            console.log("[FFmpeg]", message);
          });

          await ffmpeg.load();
          setFFmpegLoaded(true);
          setEditorMessage(null);
        } catch (error) {
          console.error("Failed to load FFmpeg", error);
          setEditorMessage(
            "Audio conversion tools could not load. Refresh and try again.",
          );
        }
      }
    };

    loadFFmpeg();
  }, []);

  useEffect(() => {
    if (waveformRef.current && !wavesurferRef.current) {
      wavesurferRef.current = WaveSurfer.create({
        container: waveformRef.current,
        waveColor: "#104e64",
        progressColor: "#ec4899",
        cursorColor: "#ec4899",
        barWidth: 3,
        barRadius: 3,
        height: 120,
        normalize: true,
      });

      const wsRegions = wavesurferRef.current.registerPlugin(
        RegionsPlugin.create(),
      );
      regionsRef.current = wsRegions;

      wavesurferRef.current.on("decode", (decodedDuration: number) => {
        setDuration(decodedDuration);
        setWaveformLoading(false);
        setEditorMessage(null);
        wsRegions.getRegions().forEach((region) => region.remove());
        wsRegions.addRegion({
          start: 0,
          end: Math.min(30, decodedDuration),
          color: "rgba(0, 255, 255, 0.3)",
          drag: true,
          resize: true,
        });
      });

      wavesurferRef.current.on("play", () => setIsPlaying(true));
      wavesurferRef.current.on("pause", () => setIsPlaying(false));
      wavesurferRef.current.on("error", (error) => {
        console.error("Waveform load error", error);
        setWaveformLoading(false);
        setEditorMessage(
          "We couldn't prepare the waveform for that sound. Please try another link.",
        );
      });

      wsRegions.on("region-updated", (region: Region) => {
        if (region.end - region.start > 30) {
          region.setOptions({ end: region.start + 30 });
        }
        region.play();
      });

      wsRegions.on("region-out", (region) => {
        region.play();
      });
    }

    return () => {
      if (wavesurferRef.current) {
        wavesurferRef.current.destroy();
        wavesurferRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    try {
      if (proxiedAudioUrl) {
        if (wavesurferRef.current) {
          setEditorMessage(null);
          setWaveformLoading(true);
          wavesurferRef.current.stop();
          regionsRef.current?.getRegions().forEach((region) => region.remove());
          wavesurferRef.current.load(proxiedAudioUrl);
        }
      } else {
        setWaveformLoading(false);
        wavesurferRef.current?.stop();
        regionsRef.current?.getRegions().forEach((region) => region.remove());
      }
    } catch (error) {
      console.log("error: ", error);
      setWaveformLoading(false);
      setEditorMessage("Something went wrong while loading the editor.");
    }
  }, [proxiedAudioUrl]);

  const handlePlayPause = () => {
    if (wavesurferRef.current) {
      wavesurferRef.current.playPause();
    }
  };

  const handleExport = useCallback(
    async (format: "ios" | "android") => {
      if (!wavesurferRef.current || !regionsRef.current || !ffmpegRef.current) {
        return;
      }

      const regions = regionsRef.current.getRegions();
      if (regions.length === 0) {
        setEditorMessage("Drag the highlighted region to choose the snippet.");
        return;
      }

      if (!ffmpegLoaded) {
        setEditorMessage("Audio converter is still loading. Give it a moment.");
        return;
      }

      setEditorMessage(null);
      setExportingFormat(format);

      const region = regions[0];
      const start = region.start;
      const end = region.end;

      const originalBuffer = wavesurferRef.current.getDecodedData();
      if (!originalBuffer) {
        setEditorMessage("Audio data is still preparing. Please wait a moment.");
        setExportingFormat(null);
        return;
      }

      const sampleRate = originalBuffer.sampleRate;
      const numChannels = originalBuffer.numberOfChannels;
      const startFrame = Math.floor(start * sampleRate);
      const endFrame = Math.floor(end * sampleRate);
      const frameCount = endFrame - startFrame;

      const interleaved = new Float32Array(frameCount * numChannels);
      for (let channel = 0; channel < numChannels; channel++) {
        const channelData = originalBuffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
          interleaved[i * numChannels + channel] = channelData[startFrame + i];
        }
      }

      const wavData = encodeWAV(interleaved, sampleRate, numChannels);
      const wavUint8 = new Uint8Array(
        wavData.buffer as ArrayBuffer,
        wavData.byteOffset,
        wavData.byteLength,
      );

      try {
        const ffmpeg = ffmpegRef.current;
        await ffmpeg.writeFile("input.wav", wavUint8);

        if (format === "ios") {
          await ffmpeg.exec([
            "-i",
            "input.wav",
            "-c:a",
            "aac",
            "-b:a",
            "128k",
            "-ar",
            "44100",
            "-ac",
            "2",
            "-f",
            "ipod",
            "output.m4r",
          ]);
        } else {
          await ffmpeg.exec([
            "-i",
            "input.wav",
            "-c:a",
            "libmp3lame",
            "-b:a",
            "192k",
            "-ar",
            "44100",
            "output.mp3",
          ]);
        }

        const outputFilename = format === "ios" ? "output.m4r" : "output.mp3";
        const outputData = (await ffmpeg.readFile(outputFilename)) as Uint8Array;
        const blob = new Blob([new Uint8Array(outputData)], {
          type: format === "ios" ? "audio/mp4" : "audio/mpeg",
        });
        const url = URL.createObjectURL(blob);

        const anchor = document.createElement("a");
        anchor.style.display = "none";
        anchor.href = url;
        anchor.download = `ringtone-${Date.now()}.${format === "ios" ? "m4r" : "mp3"}`;
        document.body.appendChild(anchor);
        anchor.click();

        setTimeout(() => {
          window.URL.revokeObjectURL(url);
          document.body.removeChild(anchor);
        }, 100);

        await ffmpeg.deleteFile("input.wav");
        await ffmpeg.deleteFile(outputFilename);
      } catch (error) {
        console.error("FFmpeg conversion error:", error);
        setEditorMessage("Export failed. Please try again.");
      } finally {
        setExportingFormat(null);
      }
    },
    [ffmpegLoaded],
  );

  return (
    <div className="w-full font-sans">
      <div className="mx-auto w-full max-w-2xl overflow-hidden rounded-[2rem] border border-white/80 bg-white shadow-[0_30px_90px_-55px_rgba(6,67,88,0.6)]">
        <div className="space-y-8 p-6 sm:p-8">
          <div className={fileLoaded ? "block" : "hidden"}>
            <div className="mb-4 flex items-center justify-between">
              <div className="flex items-center space-x-2 rounded-full bg-cyan-50 px-4 py-2">
                <Music className="h-4 w-4 text-cyan-900" />
                <span className="max-w-[150px] truncate font-medium text-cyan-900">
                  {fileName}
                </span>
              </div>
              <div className="rounded-full bg-cyan-100 px-3 py-1 text-xs font-bold uppercase tracking-widest text-cyan-900">
                Max 30s
              </div>
            </div>

            <div className="mb-4 flex flex-wrap items-center gap-3 rounded-2xl bg-cyan-50 px-4 py-3 text-sm text-cyan-900/75">
              <WandSparkles className="h-4 w-4 text-pink-500" />
              <p>Move or resize the cyan region to choose the exact ringtone slice.</p>
            </div>

            {editorMessage ? (
              <div className="mb-4 flex items-start gap-2 rounded-2xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-950">
                <AlertCircle className="mt-0.5 h-4 w-4 shrink-0" />
                <p>{editorMessage}</p>
              </div>
            ) : null}

            <div className="relative mb-6">
              <div
                ref={waveformRef}
                className="w-full overflow-hidden rounded-xl border-2 border-cyan-100 bg-cyan-50"
              />
              {waveformLoading ? (
                <div className="absolute inset-0 flex flex-col items-center justify-center gap-3 rounded-xl bg-cyan-950/7 backdrop-blur-[1px]">
                  <LoaderCircle className="h-7 w-7 animate-spin text-cyan-700" />
                  <div className="text-center">
                    <p className="text-sm font-semibold text-cyan-950">
                      Preparing waveform and trim handles...
                    </p>
                    <p className="mt-1 text-xs text-cyan-900/65">
                      The region selector will appear as soon as the audio is decoded.
                    </p>
                  </div>
                </div>
              ) : null}
            </div>

            <div className="mb-8 flex justify-center">
              <button
                onClick={handlePlayPause}
                disabled={waveformLoading}
                aria-label={isPlaying ? "Pause audio preview" : "Play audio preview"}
                className="rounded-full bg-cyan-500 p-4 text-white shadow-lg transition-all hover:scale-105 hover:bg-cyan-600 hover:shadow-xl disabled:cursor-not-allowed disabled:bg-cyan-300 disabled:hover:scale-100"
              >
                {isPlaying ? (
                  <Pause fill="currentColor" />
                ) : (
                  <Play fill="currentColor" className="ml-1" />
                )}
              </button>
            </div>

            <div className="border-t-2 border-gray-100 pt-6">
              <p className="mb-4 text-center text-sm font-medium text-gray-500">
                Ready to export? Pick your device.
              </p>
              <div className="flex gap-4">
                <button
                  onClick={() => handleExport("ios")}
                  disabled={waveformLoading || exportingFormat !== null}
                  className="group relative flex flex-1 flex-col items-center rounded-2xl border-2 border-blue-200 bg-white p-4 transition-all hover:-translate-y-1 hover:border-blue-400 disabled:cursor-not-allowed disabled:opacity-60 disabled:hover:translate-y-0"
                >
                  <div className="mb-2 rounded-full bg-blue-100 p-2 transition-colors group-hover:bg-blue-200">
                    {exportingFormat === "ios" ? (
                      <LoaderCircle className="h-6 w-6 animate-spin text-blue-500" />
                    ) : (
                      <Download className="h-6 w-6 text-blue-500" />
                    )}
                  </div>
                  <span className="font-bold text-blue-500">iPhone</span>
                  <span className="text-xs text-blue-300">.m4r</span>
                </button>

                <button
                  onClick={() => handleExport("android")}
                  disabled={waveformLoading || exportingFormat !== null}
                  className="group relative flex flex-1 flex-col items-center rounded-2xl border-2 border-green-200 bg-white p-4 transition-all hover:-translate-y-1 hover:border-green-400 disabled:cursor-not-allowed disabled:opacity-60 disabled:hover:translate-y-0"
                >
                  <div className="mb-2 rounded-full bg-green-100 p-2 transition-colors group-hover:bg-green-200">
                    {exportingFormat === "android" ? (
                      <LoaderCircle className="h-6 w-6 animate-spin text-green-500" />
                    ) : (
                      <Download className="h-6 w-6 text-green-500" />
                    )}
                  </div>
                  <span className="font-bold text-green-500">Android</span>
                  <span className="text-xs text-green-300">.mp3</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Editor;
