"use client";

import useStateData from "@/hooks/useStateData";
import { formAction } from "@/utils/form-action";
import { AlertCircle, FileSearchCorner, Link2 } from "lucide-react";
import { useState } from "react";

export default function Form() {
  const [url, setUrl] = useState<string>("");

  const { handleSetData, handleSubmitted, handleMessage, message, submitted } =
    useStateData();

  function isValidTikTokUrl(value: string) {
    try {
      const parsed = new URL(value);
      return parsed.hostname.includes("tiktok.com");
    } catch {
      return false;
    }
  }

  async function handleForm(ev: React.FormEvent<HTMLFormElement>) {
    ev.preventDefault();

    handleSubmitted(true);
    handleMessage(null);

    try {
      if (!isValidTikTokUrl(url)) {
        handleSetData(null);
        handleMessage("Paste a valid TikTok post URL to load its sound.");
        return;
      }

      const data = await formAction(url);
      handleSetData(data);
      handleMessage(null);
    } catch (error) {
      handleSetData(null);
      handleMessage(
        error instanceof Error
          ? error.message
          : "Failed to fetch TikTok audio. Please try again.",
      );
    } finally {
      handleSubmitted(false);
    }
  }

  return (
    <div className="w-full max-w-2xl">
      <form
        onSubmit={handleForm}
        className="rounded-[2rem] border border-cyan-200/70 bg-white/90 p-4 shadow-[0_24px_70px_-36px_rgba(9,62,84,0.45)] backdrop-blur sm:p-5"
      >
        <div className="mb-3 flex items-center gap-2 text-sm font-semibold text-cyan-900">
          <div className="rounded-full bg-cyan-100 p-2">
            <Link2 className="h-4 w-4" />
          </div>
          Paste a TikTok link to extract the sound
        </div>
        <div className="block gap-2 sm:flex">
          <input
            name="url"
            type="text"
            placeholder="https://www.tiktok.com/@creator/video/123456789"
            aria-label="TikTok post URL"
            className="w-full rounded-2xl border-2 border-cyan-500/70 bg-cyan-50/70 px-4 py-3 text-cyan-950 outline-none transition focus:border-cyan-700 focus:bg-white"
            value={url}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
              setUrl(e.target.value)
            }
          />
          <button
            type="submit"
            disabled={submitted}
            className="mt-2.5 flex w-full items-center justify-center gap-2 rounded-2xl bg-cyan-600 px-5 py-3 font-semibold text-cyan-50 transition hover:bg-cyan-700 active:bg-cyan-800 disabled:cursor-not-allowed disabled:bg-cyan-300 sm:mt-0 sm:w-auto"
          >
            <FileSearchCorner size={20} />
            {submitted ? "Loading..." : "Load Audio"}
          </button>
        </div>
        <p className="mt-3 text-sm text-cyan-900/70">
          We&apos;ll fetch the sound, build the waveform, and let you trim the
          best 30 seconds for ringtone export.
        </p>
        {message ? (
          <div className="mt-4 flex items-start gap-2 rounded-2xl border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-900">
            <AlertCircle className="mt-0.5 h-4 w-4 shrink-0" />
            <p>{message}</p>
          </div>
        ) : null}
      </form>
    </div>
  );
}
